#include <stdio.h>

#define N 3

int main(void) {
    int burst[] = {6, 3, 9};
    int wait[N], turnaround[N];

    wait[0] = 0;
    for (int i = 1; i < N; i++)
        wait[i] = wait[i-1] + burst[i-1];

    float total_wait = 0, total_ta = 0;
    for (int i = 0; i < N; i++) {
        turnaround[i] = wait[i] + burst[i];
        total_wait += wait[i];
        total_ta += turnaround[i];
    }

    printf("Average waiting time: %.2f\n", total_wait / N);
    printf("Average turnaround time: %.2f\n", total_ta / N);
    return 0;
}

